import React from "react";

function Stats({ stats }) {
  return (
    <div>
      <h2>Assignment Stats</h2>
      <p>Total: {stats.total}</p>
      <p>Submitted: {stats.submitted}</p>
      <p>Pending: {stats.pending}</p>
    </div>
  );
}

export default Stats;
